//! Embedded HTML pages for the web UI

/// Get HTML based on language
pub fn get_index_html(lang: &str) -> &'static str {
    match lang {
        "en" => INDEX_HTML_EN,
        "fa" => INDEX_HTML_FA,
        "ru" => INDEX_HTML_RU,
        _ => INDEX_HTML_ZH,
    }
}

